//! Monocular depth and simple mesh extrusion.
//!
//! **ONNX-first** contract: callers pass a `.onnx` depth model path when wiring `ort`/ONNX
//! Runtime locally. This crate stubs inference until [`DepthEstimator`] is implemented with your
//! chosen backend ( ONNX weights stay out-of-repo unless you explicitly vendor them ).

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum DepthError {
    OnnxDisabled,
    Onnx(String),
    Shape,
    /// Mesh-depth pipeline or topology-mask wiring error.
    Mesh(String),
}

impl std::fmt::Display for DepthError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            DepthError::OnnxDisabled => write!(f, "monocular ONNX depth not wired (stub)"),
            DepthError::Onnx(s) => write!(f, "onnx depth: {}", s),
            DepthError::Shape => write!(f, "dimensions mismatch"),
            DepthError::Mesh(s) => write!(f, "mesh depth: {}", s),
        }
    }
}

impl std::error::Error for DepthError {}

pub trait DepthEstimator {
    fn estimate_normalized(
        &mut self,
        rgb_f32_unit: &[f32],
        width: usize,
        height: usize,
    ) -> Result<Vec<f32>, DepthError>;
}

/// Stub ONNX hook: integrate `Session`/`ort::session` behind a downstream crate or feature gate.
///
/// Until then returns [`DepthError::OnnxDisabled`].
pub fn estimate_depth_monocular_normalized(
    _rgb_f32_unit: &[f32],
    _width: usize,
    _height: usize,
    _onnx_model_path: &std::path::Path,
) -> Result<Vec<f32>, DepthError> {
    let _ = _onnx_model_path;
    #[cfg(all(feature = "depth-onnx", not(target_arch = "wasm32")))]
    {
        return crate::depth_onnx::estimate_depth_onnx_file(
            _rgb_f32_unit,
            _width,
            _height,
            _onnx_model_path,
        );
    }
    #[cfg(not(all(feature = "depth-onnx", not(target_arch = "wasm32"))))]
    {
        Err(DepthError::OnnxDisabled)
    }
}

/// CI-friendly monocular **proxy** depth in `[0,1]`: inverted Rec.709 luma blended with
/// normalized 4-neighbour luma contrast (no ONNX). Linear RGB unit floats, row-major `RGB…`.
pub fn estimate_depth_classical_normalized(
    rgb_f32_unit: &[f32],
    width: usize,
    height: usize,
) -> Result<Vec<f32>, DepthError> {
    if width == 0 || height == 0 {
        return Err(DepthError::Shape);
    }
    let n = width * height;
    let need = n * 3;
    if rgb_f32_unit.len() != need {
        return Err(DepthError::Shape);
    }
    let mut luma = vec![0.0_f32; n];
    for i in 0..n {
        let o = i * 3;
        let r = rgb_f32_unit[o].clamp(0.0, 1.0);
        let g = rgb_f32_unit[o + 1].clamp(0.0, 1.0);
        let b = rgb_f32_unit[o + 2].clamp(0.0, 1.0);
        luma[i] = (0.2126 * r + 0.7152 * g + 0.0722 * b).clamp(0.0, 1.0);
    }
    let mut edge = vec![0.0_f32; n];
    for y in 0..height {
        for x in 0..width {
            let i = y * width + x;
            let c = luma[i];
            let mut acc = 0.0_f32;
            let mut cnt = 0_u32;
            for (dx, dy) in [(-1i32, 0), (1, 0), (0, -1), (0, 1)] {
                let nx = (x as i32 + dx).clamp(0, width as i32 - 1) as usize;
                let ny = (y as i32 + dy).clamp(0, height as i32 - 1) as usize;
                acc += (c - luma[ny * width + nx]).abs();
                cnt += 1;
            }
            edge[i] = acc / cnt as f32;
        }
    }
    let mut em = 0.0_f32;
    for &e in &edge {
        em = em.max(e);
    }
    if em < 1e-8 {
        em = 1.0;
    }
    let mut out = vec![0.0_f32; n];
    for i in 0..n {
        let e = (edge[i] / em).clamp(0.0, 1.0);
        let inv = 1.0 - luma[i];
        out[i] = (0.65 * inv + 0.35 * e).clamp(0.0, 1.0);
    }
    // Single 3×3 box smooth (reuse topology-style blur inline)
    let tmp = out.clone();
    for y in 0..height {
        for x in 0..width {
            let mut s = 0.0_f32;
            for dy in -1i32..=1 {
                for dx in -1i32..=1 {
                    let nx = (x as i32 + dx).clamp(0, width as i32 - 1) as usize;
                    let ny = (y as i32 + dy).clamp(0, height as i32 - 1) as usize;
                    s += tmp[ny * width + nx];
                }
            }
            out[y * width + x] = (s / 9.0).clamp(0.0, 1.0);
        }
    }
    Ok(out)
}

#[derive(Clone, Debug)]
pub struct TriMeshRgb {
    pub positions: Vec<f32>, // xyz xyz ...
    pub uvs_or_colors: Vec<f32>,
    pub indices: Vec<u32>,
}

/// Simple heightfield: grid in XY, Z = `(depth[p]-0.5) * exaggeration`.
pub fn extrude_depth_heightfield_rgb(
    depth_unit: &[f32],
    rgb_unit: &[f32],
    width: usize,
    height: usize,
    exaggeration: f32,
) -> Result<TriMeshRgb, DepthError> {
    let n = width * height;
    if depth_unit.len() != n || rgb_unit.len() != n * 3 {
        return Err(DepthError::Shape);
    }
    let ex = exaggeration;
    let mut positions = Vec::with_capacity(n * 3);
    let mut colors = Vec::with_capacity(n * 3);

    let fx = |x: usize| ((x as f32 + 0.5) / width as f32 - 0.5) * 2.0;
    let fy = |y: usize| ((height as f32 - y as f32 - 0.5) / height as f32 - 0.5) * 2.0;

    for y in 0..height {
        for x in 0..width {
            let p = y * width + x;
            let z = (depth_unit[p] - 0.5) * 2.0 * ex;
            positions.push(fx(x));
            positions.push(fy(y));
            positions.push(z);
            let o = p * 3;
            colors.push(rgb_unit[o]);
            colors.push(rgb_unit[o + 1]);
            colors.push(rgb_unit[o + 2]);
        }
    }

    let mut indices = Vec::with_capacity((width - 1) * (height - 1) * 6);
    for y in 0..height - 1 {
        for x in 0..width - 1 {
            let i0 = (y * width + x) as u32;
            let i1 = i0 + 1;
            let i2 = i0 + width as u32;
            let i3 = i2 + 1;
            indices.extend_from_slice(&[i0, i1, i3, i0, i3, i2]);
        }
    }

    Ok(TriMeshRgb {
        positions,
        uvs_or_colors: colors,
        indices,
    })
}

/// Heightfield extrusion with per-vertex Z scaled by `confidence` in `[0,1]` (topology / sieve admission).
pub fn extrude_depth_heightfield_rgb_weighted(
    depth_unit: &[f32],
    confidence: &[f32],
    rgb_unit: &[f32],
    width: usize,
    height: usize,
    exaggeration: f32,
) -> Result<TriMeshRgb, DepthError> {
    let n = width * height;
    if depth_unit.len() != n || confidence.len() != n || rgb_unit.len() != n * 3 {
        return Err(DepthError::Shape);
    }
    let ex = exaggeration;
    let mut positions = Vec::with_capacity(n * 3);
    let mut colors = Vec::with_capacity(n * 3);
    let fx = |x: usize| ((x as f32 + 0.5) / width as f32 - 0.5) * 2.0;
    let fy = |y: usize| ((height as f32 - y as f32 - 0.5) / height as f32 - 0.5) * 2.0;
    for y in 0..height {
        for x in 0..width {
            let p = y * width + x;
            let c = confidence[p].clamp(0.0, 1.0);
            let z = (depth_unit[p] - 0.5) * 2.0 * ex * c;
            positions.push(fx(x));
            positions.push(fy(y));
            positions.push(z);
            let o = p * 3;
            colors.push(rgb_unit[o]);
            colors.push(rgb_unit[o + 1]);
            colors.push(rgb_unit[o + 2]);
        }
    }
    let mut indices = Vec::with_capacity((width - 1) * (height - 1) * 6);
    for y in 0..height - 1 {
        for x in 0..width - 1 {
            let i0 = (y * width + x) as u32;
            let i1 = i0 + 1;
            let i2 = i0 + width as u32;
            let i3 = i2 + 1;
            indices.extend_from_slice(&[i0, i1, i3, i0, i3, i2]);
        }
    }
    Ok(TriMeshRgb {
        positions,
        uvs_or_colors: colors,
        indices,
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn extrude_quad_two_tris_six_indices() {
        let w = 2_usize;
        let h = 2_usize;
        let depth = vec![0.5_f32; w * h];
        let rgb = vec![1.0_f32; w * h * 3];
        let m = extrude_depth_heightfield_rgb(&depth, &rgb, w, h, 0.1).unwrap();
        assert_eq!(m.positions.len(), w * h * 3);
        assert_eq!(m.indices.len(), 6);
    }

    #[test]
    fn onnx_stub_errors() {
        let rgb = vec![0.5_f32; 12];
        let p = std::path::Path::new("/dev/null");
        assert!(matches!(
            estimate_depth_monocular_normalized(&rgb, 2, 2, p),
            Err(DepthError::OnnxDisabled)
        ));
    }

    #[test]
    fn classical_depth_in_unit_range() {
        let w = 4_usize;
        let h = 4_usize;
        let rgb = vec![0.3_f32; w * h * 3];
        let d = estimate_depth_classical_normalized(&rgb, w, h).unwrap();
        assert_eq!(d.len(), w * h);
        assert!(d.iter().all(|&x| x >= 0.0 && x <= 1.0));
    }

    #[test]
    fn weighted_extrusion_reduces_z_spread_vs_full() {
        let w = 4_usize;
        let h = 4_usize;
        let n = w * h;
        let depth = vec![0.8_f32; n];
        let conf = vec![0.25_f32; n];
        let rgb = vec![0.5_f32; n * 3];
        let ex = 1.0_f32;
        let m_w = extrude_depth_heightfield_rgb_weighted(&depth, &conf, &rgb, w, h, ex).unwrap();
        let m_f = extrude_depth_heightfield_rgb(&depth, &rgb, w, h, ex).unwrap();
        let z_w: f32 = m_w
            .positions
            .iter()
            .skip(2)
            .step_by(3)
            .map(|z| z.abs())
            .sum();
        let z_f: f32 = m_f
            .positions
            .iter()
            .skip(2)
            .step_by(3)
            .map(|z| z.abs())
            .sum();
        assert!(
            z_w < z_f,
            "weighted Z sum should be lower when confidence<1"
        );
    }
}
